     1→import { ChildProcess } from 'child_process';
     2→import { CronExpressionParser } from 'cron-parser';
     3→import fs from 'fs';
     4→
     5→import { ASSISTANT_NAME, SCHEDULER_POLL_INTERVAL, TIMEZONE } from './config.js';
     6→import { ContainerOutput, runContainerAgent } from './container-runner.js';
     7→import {
     8→  getDueTasks,
     9→  getTaskById,
    10→  logTaskRun,
    11→  updateTask,
    12→  updateTaskAfterRun,
    13→} from './db.js';
    14→import { GroupQueue } from './group-queue.js';
    15→import { prepareAndWriteSnapshots } from './snapshots.js';
    16→import { resolveGroupFolderPath } from './group-folder.js';
    17→import { logger } from './logger.js';
    18→import { RegisteredGroup, ScheduledTask } from './types.js';
    19→
    20→/**
    21→ * Compute the next run time for a recurring task, anchored to the
    22→ * task's scheduled time rather than Date.now() to prevent cumulative
    23→ * drift on interval-based tasks.
    24→ *
    25→ * Co-authored-by: @community-pr-601
    26→ */
    27→export function computeNextRun(task: ScheduledTask): string | null {
    28→  if (task.schedule_type === 'once') return null;
    29→
    30→  const now = Date.now();
    31→
    32→  if (task.schedule_type === 'cron') {
    33→    const interval = CronExpressionParser.parse(task.schedule_value, {
    34→      tz: TIMEZONE,
    35→    });
    36→    return interval.next().toISOString();
    37→  }
    38→
    39→  if (task.schedule_type === 'interval') {
    40→    const ms = parseInt(task.schedule_value, 10);
    41→    if (!ms || ms <= 0) {
    42→      // Guard against malformed interval that would cause an infinite loop
    43→      logger.warn(
    44→        { taskId: task.id, value: task.schedule_value },
    45→        'Invalid interval value',
    46→      );
    47→      return new Date(now + 60_000).toISOString();
    48→    }
    49→    // Anchor to the scheduled time, not now, to prevent drift.
    50→    // Skip past any missed intervals so we always land in the future.
    51→    let next = new Date(task.next_run!).getTime() + ms;
    52→    while (next <= now) {
    53→      next += ms;
    54→    }
    55→    return new Date(next).toISOString();
    56→  }
    57→
    58→  return null;
    59→}
    60→
    61→export interface SchedulerDependencies {
    62→  registeredGroups: () => Record<string, RegisteredGroup>;
    63→  getSessions: () => Record<string, string>;
    64→  queue: GroupQueue;
    65→  onProcess: (
    66→    groupJid: string,
    67→    proc: ChildProcess,
    68→    containerName: string,
    69→    groupFolder: string,
    70→  ) => void;
    71→  sendMessage: (jid: string, text: string) => Promise<void>;
    72→}
    73→
    74→async function runTask(
    75→  task: ScheduledTask,
    76→  deps: SchedulerDependencies,
    77→): Promise<void> {
    78→  const startTime = Date.now();
    79→  let groupDir: string;
    80→  try {
    81→    groupDir = resolveGroupFolderPath(task.group_folder);
    82→  } catch (err) {
    83→    const error = err instanceof Error ? err.message : String(err);
    84→    // Stop retry churn for malformed legacy rows.
    85→    updateTask(task.id, { status: 'paused' });
    86→    logger.error(
    87→      { taskId: task.id, groupFolder: task.group_folder, error },
    88→      'Task has invalid group folder',
    89→    );
    90→    logTaskRun({
    91→      task_id: task.id,
    92→      run_at: new Date().toISOString(),
    93→      duration_ms: Date.now() - startTime,
    94→      status: 'error',
    95→      result: null,
    96→      error,
    97→    });
    98→    return;
    99→  }
   100→  fs.mkdirSync(groupDir, { recursive: true });
   101→
   102→  logger.info(
   103→    { taskId: task.id, group: task.group_folder },
   104→    'Running scheduled task',
   105→  );
   106→
   107→  const groups = deps.registeredGroups();
   108→  const group = Object.values(groups).find(
   109→    (g) => g.folder === task.group_folder,
   110→  );
   111→
   112→  if (!group) {
   113→    logger.error(
   114→      { taskId: task.id, groupFolder: task.group_folder },
   115→      'Group not found for task',
   116→    );
   117→    logTaskRun({
   118→      task_id: task.id,
   119→      run_at: new Date().toISOString(),
   120→      duration_ms: Date.now() - startTime,
   121→      status: 'error',
   122→      result: null,
   123→      error: `Group not found: ${task.group_folder}`,
   124→    });
   125→    return;
   126→  }
   127→
   128→  const isMain = group.isMain === true;
   129→  prepareAndWriteSnapshots(task.group_folder, isMain, groups);
   130→
   131→  let result: string | null = null;
   132→  let error: string | null = null;
   133→
   134→  // For group context mode, use the group's current session
   135→  const sessions = deps.getSessions();
   136→  const sessionId =
   137→    task.context_mode === 'group' ? sessions[task.group_folder] : undefined;
   138→
   139→  // After the task produces a result, close the container promptly.
   140→  // Tasks are single-turn — no need to wait IDLE_TIMEOUT (30 min) for the
   141→  // query loop to time out. A short delay handles any final MCP calls.
   142→  const TASK_CLOSE_DELAY_MS = 10000;
   143→  let closeTimer: ReturnType<typeof setTimeout> | null = null;
   144→
   145→  const scheduleClose = () => {
   146→    if (closeTimer) return; // already scheduled
   147→    closeTimer = setTimeout(() => {
   148→      logger.debug({ taskId: task.id }, 'Closing task container after result');
   149→      deps.queue.closeStdin(task.chat_jid);
   150→    }, TASK_CLOSE_DELAY_MS);
   151→  };
   152→
   153→  try {
   154→    const output = await runContainerAgent(
   155→      group,
   156→      {
   157→        prompt: task.prompt,
   158→        sessionId,
   159→        groupFolder: task.group_folder,
   160→        chatJid: task.chat_jid,
   161→        isMain,
   162→        isScheduledTask: true,
   163→        assistantName: ASSISTANT_NAME,
   164→      },
   165→      (proc, containerName) =>
   166→        deps.onProcess(task.chat_jid, proc, containerName, task.group_folder),
   167→      async (streamedOutput: ContainerOutput) => {
   168→        if (streamedOutput.result) {
   169→          result = streamedOutput.result;
   170→          // Forward result to user (sendMessage handles formatting)
   171→          await deps.sendMessage(task.chat_jid, streamedOutput.result);
   172→          scheduleClose();
   173→        }
   174→        if (streamedOutput.status === 'success') {
   175→          deps.queue.notifyIdle(task.chat_jid);
   176→          scheduleClose(); // Close promptly even when result is null (e.g. IPC-only tasks)
   177→        }
   178→        if (streamedOutput.status === 'error') {
   179→          error = streamedOutput.error || 'Unknown error';
   180→        }
   181→      },
   182→    );
   183→
   184→    if (closeTimer) clearTimeout(closeTimer);
   185→
   186→    if (output.status === 'error') {
   187→      error = output.error || 'Unknown error';
   188→    } else if (output.result) {
   189→      // Result was already forwarded to the user via the streaming callback above
   190→      result = output.result;
   191→    }
   192→
   193→    logger.info(
   194→      { taskId: task.id, durationMs: Date.now() - startTime },
   195→      'Task completed',
   196→    );
   197→  } catch (err) {
   198→    if (closeTimer) clearTimeout(closeTimer);
   199→    error = err instanceof Error ? err.message : String(err);
   200→    logger.error({ taskId: task.id, error }, 'Task failed');
   201→  }
   202→
   203→  const durationMs = Date.now() - startTime;
   204→
   205→  logTaskRun({
   206→    task_id: task.id,
   207→    run_at: new Date().toISOString(),
   208→    duration_ms: durationMs,
   209→    status: error ? 'error' : 'success',
   210→    result,
   211→    error,
   212→  });
   213→
   214→  const nextRun = computeNextRun(task);
   215→  const resultSummary = error
   216→    ? `Error: ${error}`
   217→    : result
   218→      ? result.slice(0, 200)
   219→      : 'Completed';
   220→  updateTaskAfterRun(task.id, nextRun, resultSummary);
   221→}
   222→
   223→let schedulerRunning = false;
   224→
   225→export function startSchedulerLoop(deps: SchedulerDependencies): void {
   226→  if (schedulerRunning) {
   227→    logger.debug('Scheduler loop already running, skipping duplicate start');
   228→    return;
   229→  }
   230→  schedulerRunning = true;
   231→  logger.info('Scheduler loop started');
   232→
   233→  const loop = async () => {
   234→    try {
   235→      const dueTasks = getDueTasks();
   236→      if (dueTasks.length > 0) {
   237→        logger.info({ count: dueTasks.length }, 'Found due tasks');
   238→      }
   239→
   240→      for (const task of dueTasks) {
   241→        // Re-check task status in case it was paused/cancelled
   242→        const currentTask = getTaskById(task.id);
   243→        if (!currentTask || currentTask.status !== 'active') {
   244→          continue;
   245→        }
   246→
   247→        deps.queue.enqueueTask(currentTask.chat_jid, currentTask.id, () =>
   248→          runTask(currentTask, deps),
   249→        );
   250→      }
   251→    } catch (err) {
   252→      logger.error({ err }, 'Error in scheduler loop');
   253→    }
   254→
   255→    setTimeout(loop, SCHEDULER_POLL_INTERVAL);
   256→  };
   257→
   258→  loop();
   259→}
   260→
   261→/** @internal - for tests only. */
   262→export function _resetSchedulerLoopForTests(): void {
   263→  schedulerRunning = false;
   264→}
   265→

