    10→describe('task scheduler', () => {
    11→  beforeEach(() => {
    12→    _initTestDatabase();
    13→    _resetSchedulerLoopForTests();
    14→    vi.useFakeTimers();
    15→  });
    16→
    17→  afterEach(() => {
    18→    vi.useRealTimers();
    19→  });
    20→
    21→  it('pauses due tasks with invalid group folders to prevent retry churn', async () => {
    22→    createTask({
    23→      id: 'task-invalid-folder',
    24→      group_folder: '../../outside',
    25→      chat_jid: 'bad@g.us',
    26→      prompt: 'run',
    27→      schedule_type: 'once',
    28→      schedule_value: '2026-02-22T00:00:00.000Z',
    29→      context_mode: 'isolated',
    30→      next_run: new Date(Date.now() - 60_000).toISOString(),
    31→      status: 'active',
    32→      created_at: '2026-02-22T00:00:00.000Z',
    33→    });
    34→
    35→    const enqueueTask = vi.fn(
    36→      (_groupJid: string, _taskId: string, fn: () => Promise<void>) => {
    37→        void fn();
    38→      },
    39→    );
    40→
    41→    startSchedulerLoop({
    42→      registeredGroups: () => ({}),
    43→      getSessions: () => ({}),
    44→      queue: { enqueueTask } as any,
    45→      onProcess: () => {},
    46→      sendMessage: async () => {},
    47→    });
    48→
    49→    await vi.advanceTimersByTimeAsync(10);
    50→
    51→    const task = getTaskById('task-invalid-folder');
    52→    expect(task?.status).toBe('paused');
    53→  });
    54→
    55→  it('computeNextRun anchors interval tasks to scheduled time to prevent drift', () => {
    56→    const scheduledTime = new Date(Date.now() - 2000).toISOString(); // 2s ago
    57→    const task = {
    58→      id: 'drift-test',
    59→      group_folder: 'test',
    60→      chat_jid: 'test@g.us',
    61→      prompt: 'test',
    62→      schedule_type: 'interval' as const,
    63→      schedule_value: '60000', // 1 minute
    64→      context_mode: 'isolated' as const,
    65→      next_run: scheduledTime,
    66→      last_run: null,
    67→      last_result: null,
    68→      status: 'active' as const,
    69→      created_at: '2026-01-01T00:00:00.000Z',
    70→    };
    71→
    72→    const nextRun = computeNextRun(task);
    73→    expect(nextRun).not.toBeNull();
    74→
    75→    // Should be anchored to scheduledTime + 60s, NOT Date.now() + 60s
    76→    const expected = new Date(scheduledTime).getTime() + 60000;
    77→    expect(new Date(nextRun!).getTime()).toBe(expected);
    78→  });
    79→
    80→  it('computeNextRun returns null for once-tasks', () => {
    81→    const task = {
    82→      id: 'once-test',
    83→      group_folder: 'test',
    84→      chat_jid: 'test@g.us',
    85→      prompt: 'test',
    86→      schedule_type: 'once' as const,
    87→      schedule_value: '2026-01-01T00:00:00.000Z',
    88→      context_mode: 'isolated' as const,
    89→      next_run: new Date(Date.now() - 1000).toISOString(),
    90→      last_run: null,
    91→      last_result: null,
    92→      status: 'active' as const,
    93→      created_at: '2026-01-01T00:00:00.000Z',
    94→    };
    95→
    96→    expect(computeNextRun(task)).toBeNull();
    97→  });
    98→
    99→  it('computeNextRun skips missed intervals without infinite loop', () => {
   100→    // Task was due 10 intervals ago (missed)
   101→    const ms = 60000;
   102→    const missedBy = ms * 10;
   103→    const scheduledTime = new Date(Date.now() - missedBy).toISOString();
   104→
   105→    const task = {
   106→      id: 'skip-test',
   107→      group_folder: 'test',
   108→      chat_jid: 'test@g.us',
   109→      prompt: 'test',
   110→      schedule_type: 'interval' as const,
   111→      schedule_value: String(ms),
   112→      context_mode: 'isolated' as const,
   113→      next_run: scheduledTime,
   114→      last_run: null,
   115→      last_result: null,
   116→      status: 'active' as const,
   117→      created_at: '2026-01-01T00:00:00.000Z',
   118→    };
   119→
   120→    const nextRun = computeNextRun(task);
   121→    expect(nextRun).not.toBeNull();
   122→    // Must be in the future
   123→    expect(new Date(nextRun!).getTime()).toBeGreaterThan(Date.now());
   124→    // Must be aligned to the original schedule grid
   125→    const offset =
   126→      (new Date(nextRun!).getTime() - new Date(scheduledTime).getTime()) % ms;
   127→    expect(offset).toBe(0);
   128→  });
   129→});
