     1→import { ChildProcess } from 'child_process';
     2→import fs from 'fs';
     3→import path from 'path';
     4→
     5→import { DATA_DIR, MAX_CONCURRENT_CONTAINERS } from './config.js';
     6→import { logger } from './logger.js';
     7→
     8→interface QueuedTask {
     9→  id: string;
    10→  groupJid: string;
    11→  fn: () => Promise<void>;
    12→}
    13→
    14→const MAX_RETRIES = 5;
    15→const BASE_RETRY_MS = 5000;
    16→
    17→interface GroupState {
    18→  active: boolean;
    19→  idleWaiting: boolean;
    20→  isTaskContainer: boolean;
    21→  runningTaskId: string | null;
    22→  pendingMessages: boolean;
    23→  pendingTasks: QueuedTask[];
    24→  process: ChildProcess | null;
    25→  containerName: string | null;
    26→  groupFolder: string | null;
    27→  retryCount: number;
    28→}
    29→
    30→export class GroupQueue {
    31→  private groups = new Map<string, GroupState>();
    32→  private activeCount = 0;
    33→  private waitingGroups: string[] = [];
    34→  private processMessagesFn: ((groupJid: string) => Promise<boolean>) | null =
    35→    null;
    36→  private shuttingDown = false;
    37→
    38→  private getGroup(groupJid: string): GroupState {
    39→    let state = this.groups.get(groupJid);
    40→    if (!state) {
    41→      state = {
    42→        active: false,
    43→        idleWaiting: false,
    44→        isTaskContainer: false,
    45→        runningTaskId: null,
    46→        pendingMessages: false,
    47→        pendingTasks: [],
    48→        process: null,
    49→        containerName: null,
    50→        groupFolder: null,
    51→        retryCount: 0,
    52→      };
    53→      this.groups.set(groupJid, state);
    54→    }
    55→    return state;
    56→  }
    57→
    58→  setProcessMessagesFn(fn: (groupJid: string) => Promise<boolean>): void {
    59→    this.processMessagesFn = fn;
    60→  }
    61→
    62→  enqueueMessageCheck(groupJid: string): void {
    63→    if (this.shuttingDown) return;
    64→
    65→    const state = this.getGroup(groupJid);
    66→
    67→    if (state.active) {
    68→      state.pendingMessages = true;
    69→      logger.debug({ groupJid }, 'Container active, message queued');
    70→      return;
    71→    }
    72→
    73→    if (this.activeCount >= MAX_CONCURRENT_CONTAINERS) {
    74→      state.pendingMessages = true;
    75→      if (!this.waitingGroups.includes(groupJid)) {
    76→        this.waitingGroups.push(groupJid);
    77→      }
    78→      logger.debug(
    79→        { groupJid, activeCount: this.activeCount },
    80→        'At concurrency limit, message queued',
    81→      );
    82→      return;
    83→    }
    84→
    85→    this.runForGroup(groupJid, 'messages').catch((err) =>
    86→      logger.error({ groupJid, err }, 'Unhandled error in runForGroup'),
    87→    );
    88→  }
    89→
    90→  enqueueTask(groupJid: string, taskId: string, fn: () => Promise<void>): void {
    91→    if (this.shuttingDown) return;
    92→
    93→    const state = this.getGroup(groupJid);
    94→
    95→    // Prevent double-queuing: check both pending and currently-running task
    96→    if (state.runningTaskId === taskId) {
    97→      logger.debug({ groupJid, taskId }, 'Task already running, skipping');
    98→      return;
    99→    }
   100→    if (state.pendingTasks.some((t) => t.id === taskId)) {
   101→      logger.debug({ groupJid, taskId }, 'Task already queued, skipping');
   102→      return;
   103→    }
   104→
   105→    if (state.active) {
   106→      state.pendingTasks.push({ id: taskId, groupJid, fn });
   107→      if (state.idleWaiting) {
   108→        this.closeStdin(groupJid);
   109→      }
   110→      logger.debug({ groupJid, taskId }, 'Container active, task queued');
   111→      return;
   112→    }
   113→
   114→    if (this.activeCount >= MAX_CONCURRENT_CONTAINERS) {
   115→      state.pendingTasks.push({ id: taskId, groupJid, fn });
   116→      if (!this.waitingGroups.includes(groupJid)) {
   117→        this.waitingGroups.push(groupJid);
   118→      }
   119→      logger.debug(
   120→        { groupJid, taskId, activeCount: this.activeCount },
   121→        'At concurrency limit, task queued',
   122→      );
   123→      return;
   124→    }
   125→
   126→    // Run immediately
   127→    this.runTask(groupJid, { id: taskId, groupJid, fn }).catch((err) =>
   128→      logger.error({ groupJid, taskId, err }, 'Unhandled error in runTask'),
   129→    );
   130→  }
   131→
   132→  registerProcess(
   133→    groupJid: string,
   134→    proc: ChildProcess,
   135→    containerName: string,
   136→    groupFolder?: string,
   137→  ): void {
   138→    const state = this.getGroup(groupJid);
   139→    state.process = proc;
   140→    state.containerName = containerName;
   141→    if (groupFolder) state.groupFolder = groupFolder;
   142→  }
   143→
   144→  /**
   145→   * Kill the active container for a group immediately.
   146→   * Returns true if a container was running and was killed.
   147→   */
   148→  killActive(groupJid: string): boolean {
   149→    const state = this.groups.get(groupJid);
   150→    if (!state?.active) return false;
   151→
   152→    const name = state.containerName;
   153→    const proc = state.process;
   154→
   155→    if (proc && !proc.killed) {
   156→      try {
   157→        proc.kill('SIGTERM');
   158→      } catch {
   159→        /* ignore */
   160→      }
   161→    }
   162→    if (name) {
   163→      try {
   164→        const { execSync } =
   165→          require('child_process') as typeof import('child_process');
   166→        execSync(`docker stop -t 1 ${name}`, {
   167→          stdio: 'ignore',
   168→          timeout: 5000,
   169→        });
   170→      } catch {
   171→        /* ignore */
   172→      }
   173→    }
   174→
   175→    logger.info(
   176→      { groupJid, containerName: name },
   177→      'Container killed by user request',
   178→    );
   179→    return true;
   180→  }
   181→
   182→  /**
   183→   * Mark the container as idle-waiting (finished work, waiting for IPC input).
   184→   * If tasks are pending, preempt the idle container immediately.
   185→   */
   186→  notifyIdle(groupJid: string): void {
   187→    const state = this.getGroup(groupJid);
   188→    state.idleWaiting = true;
   189→    if (state.pendingTasks.length > 0) {
   190→      this.closeStdin(groupJid);
   191→    }
   192→  }
   193→
   194→  /**
   195→   * Send a follow-up message to the active container via IPC file.
   196→   * Returns true if the message was written, false if no active container.
   197→   */
   198→  sendMessage(groupJid: string, text: string): boolean {
   199→    const state = this.getGroup(groupJid);
   200→    if (!state.active || !state.groupFolder || state.isTaskContainer)
   201→      return false;
   202→    state.idleWaiting = false; // Agent is about to receive work, no longer idle
   203→
   204→    const inputDir = path.join(DATA_DIR, 'ipc', state.groupFolder, 'input');
   205→    try {
   206→      fs.mkdirSync(inputDir, { recursive: true });
   207→      const filename = `${Date.now()}-${Math.random().toString(36).slice(2, 6)}.json`;
   208→      const filepath = path.join(inputDir, filename);
   209→      const tempPath = `${filepath}.tmp`;
   210→      fs.writeFileSync(tempPath, JSON.stringify({ type: 'message', text }));
   211→      fs.renameSync(tempPath, filepath);
   212→      return true;
   213→    } catch {
   214→      return false;
   215→    }
   216→  }
   217→
   218→  /**
   219→   * Signal the active container to wind down by writing a close sentinel.
   220→   */
   221→  closeStdin(groupJid: string): void {
   222→    const state = this.getGroup(groupJid);
   223→    if (!state.active || !state.groupFolder) return;
   224→
   225→    const inputDir = path.join(DATA_DIR, 'ipc', state.groupFolder, 'input');
   226→    try {
   227→      fs.mkdirSync(inputDir, { recursive: true });
   228→      fs.writeFileSync(path.join(inputDir, '_close'), '');
   229→    } catch {
   230→      // ignore
   231→    }
   232→  }
