   234→  /**
   235→   * Pre-spawn a persistent container for a group.
   236→   * Sets active=true for the lifetime of the container so messages route via IPC.
   237→   * Returns when the container exits. Caller is responsible for restart logic.
   238→   */
   239→  async prespawn(
   240→    groupJid: string,
   241→    groupFolder: string,
   242→    spawnFn: () => Promise<void>,
   243→  ): Promise<void> {
   244→    const state = this.getGroup(groupJid);
   245→    if (state.active || this.shuttingDown) return;
   246→
   247→    state.active = true;
   248→    state.idleWaiting = false;
   249→    state.isTaskContainer = false;
   250→    state.pendingMessages = false;
   251→    state.groupFolder = groupFolder;
   252→    this.activeCount++;
   253→
   254→    logger.info(
   255→      { groupJid, activeCount: this.activeCount },
   256→      'Pre-spawning container',
   257→    );
   258→
   259→    try {
   260→      await spawnFn();
   261→    } catch (err) {
   262→      logger.error({ groupJid, err }, 'Pre-spawn container error');
   263→    } finally {
   264→      state.active = false;
   265→      state.process = null;
   266→      state.containerName = null;
   267→      state.groupFolder = null;
   268→      this.activeCount--;
   269→      // Drain pending messages that arrived during the container's lifetime or restart gap
   270→      this.drainGroup(groupJid);
   271→    }
   272→  }
   273→
   274→  private async runForGroup(
   275→    groupJid: string,
   276→    reason: 'messages' | 'drain',
   277→  ): Promise<void> {
   278→    const state = this.getGroup(groupJid);
   279→    state.active = true;
   280→    state.idleWaiting = false;
   281→    state.isTaskContainer = false;
   282→    state.pendingMessages = false;
   283→    this.activeCount++;
   284→
   285→    logger.debug(
   286→      { groupJid, reason, activeCount: this.activeCount },
   287→      'Starting container for group',
   288→    );
   289→
   290→    try {
   291→      if (this.processMessagesFn) {
   292→        const success = await this.processMessagesFn(groupJid);
   293→        if (success) {
   294→          state.retryCount = 0;
   295→        } else {
   296→          this.scheduleRetry(groupJid, state);
   297→        }
   298→      }
   299→    } catch (err) {
   300→      logger.error({ groupJid, err }, 'Error processing messages for group');
   301→      this.scheduleRetry(groupJid, state);
   302→    } finally {
   303→      state.active = false;
   304→      state.process = null;
   305→      state.containerName = null;
   306→      state.groupFolder = null;
   307→      this.activeCount--;
   308→      this.drainGroup(groupJid);
   309→    }
   310→  }
   311→
   312→  private async runTask(groupJid: string, task: QueuedTask): Promise<void> {
   313→    const state = this.getGroup(groupJid);
   314→    state.active = true;
   315→    state.idleWaiting = false;
   316→    state.isTaskContainer = true;
   317→    state.runningTaskId = task.id;
   318→    this.activeCount++;
   319→
   320→    logger.debug(
   321→      { groupJid, taskId: task.id, activeCount: this.activeCount },
   322→      'Running queued task',
   323→    );
   324→
   325→    try {
   326→      await task.fn();
   327→    } catch (err) {
   328→      logger.error({ groupJid, taskId: task.id, err }, 'Error running task');
   329→    } finally {
   330→      state.active = false;
   331→      state.isTaskContainer = false;
   332→      state.runningTaskId = null;
   333→      state.process = null;
   334→      state.containerName = null;
   335→      state.groupFolder = null;
   336→      this.activeCount--;
   337→      this.drainGroup(groupJid);
   338→    }
   339→  }
   340→
   341→  private scheduleRetry(groupJid: string, state: GroupState): void {
   342→    state.retryCount++;
   343→    if (state.retryCount > MAX_RETRIES) {
   344→      logger.error(
   345→        { groupJid, retryCount: state.retryCount },
   346→        'Max retries exceeded, dropping messages (will retry on next incoming message)',
   347→      );
   348→      state.retryCount = 0;
   349→      return;
   350→    }
   351→
   352→    const delayMs = BASE_RETRY_MS * Math.pow(2, state.retryCount - 1);
   353→    logger.info(
   354→      { groupJid, retryCount: state.retryCount, delayMs },
   355→      'Scheduling retry with backoff',
   356→    );
   357→    setTimeout(() => {
   358→      if (!this.shuttingDown) {
   359→        this.enqueueMessageCheck(groupJid);
   360→      }
   361→    }, delayMs);
   362→  }
   363→
   364→  private drainGroup(groupJid: string): void {
   365→    if (this.shuttingDown) return;
   366→
   367→    const state = this.getGroup(groupJid);
   368→
   369→    // Tasks first (they won't be re-discovered from SQLite like messages)
   370→    if (state.pendingTasks.length > 0) {
   371→      const task = state.pendingTasks.shift()!;
   372→      this.runTask(groupJid, task).catch((err) =>
   373→        logger.error(
   374→          { groupJid, taskId: task.id, err },
   375→          'Unhandled error in runTask (drain)',
   376→        ),
   377→      );
   378→      return;
   379→    }
   380→
   381→    // Then pending messages
   382→    if (state.pendingMessages) {
   383→      this.runForGroup(groupJid, 'drain').catch((err) =>
   384→        logger.error(
   385→          { groupJid, err },
   386→          'Unhandled error in runForGroup (drain)',
   387→        ),
   388→      );
   389→      return;
   390→    }
   391→
   392→    // Nothing pending for this group; check if other groups are waiting for a slot
   393→    this.drainWaiting();
   394→  }
   395→
   396→  private drainWaiting(): void {
   397→    while (
   398→      this.waitingGroups.length > 0 &&
   399→      this.activeCount < MAX_CONCURRENT_CONTAINERS
   400→    ) {
   401→      const nextJid = this.waitingGroups.shift()!;
   402→      const state = this.getGroup(nextJid);
   403→
   404→      // Prioritize tasks over messages
   405→      if (state.pendingTasks.length > 0) {
   406→        const task = state.pendingTasks.shift()!;
   407→        this.runTask(nextJid, task).catch((err) =>
   408→          logger.error(
   409→            { groupJid: nextJid, taskId: task.id, err },
   410→            'Unhandled error in runTask (waiting)',
   411→          ),
   412→        );
   413→      } else if (state.pendingMessages) {
   414→        this.runForGroup(nextJid, 'drain').catch((err) =>
   415→          logger.error(
   416→            { groupJid: nextJid, err },
   417→            'Unhandled error in runForGroup (waiting)',
   418→          ),
   419→        );
   420→      }
   421→      // If neither pending, skip this group
   422→    }
   423→  }
   424→
   425→  async shutdown(_gracePeriodMs: number): Promise<void> {
   426→    this.shuttingDown = true;
   427→
   428→    // Count active containers but don't kill them — they'll finish on their own
   429→    // via idle timeout or container timeout. The --rm flag cleans them up on exit.
   430→    // This prevents WhatsApp reconnection restarts from killing working agents.
   431→    const activeContainers: string[] = [];
   432→    for (const [jid, state] of this.groups) {
   433→      if (state.process && !state.process.killed && state.containerName) {
   434→        activeContainers.push(state.containerName);
   435→      }
   436→    }
   437→
   438→    logger.info(
   439→      { activeCount: this.activeCount, detachedContainers: activeContainers },
   440→      'GroupQueue shutting down (containers detached, not killed)',
   441→    );
   442→  }
   443→}
