   105→
   106→  it('safeUnlink tolerates ENOENT', () => {
   107→    // Simulates the safeUnlink pattern from ipc.ts
   108→    const safeUnlink = (filePath: string) => {
   109→      try {
   110→        fs.unlinkSync(filePath);
   111→      } catch (e: unknown) {
   112→        if ((e as NodeJS.ErrnoException).code !== 'ENOENT') throw e;
   113→      }
   114→    };
   115→
   116→    const nonexistent = path.join(tmpDir, 'gone.json');
   117→    expect(() => safeUnlink(nonexistent)).not.toThrow();
   118→  });
   119→
   120→  it('safeUnlink rethrows non-ENOENT errors', () => {
   121→    const safeUnlink = (filePath: string) => {
   122→      try {
   123→        fs.unlinkSync(filePath);
   124→      } catch (e: unknown) {
   125→        if ((e as NodeJS.ErrnoException).code !== 'ENOENT') throw e;
   126→      }
   127→    };
   128→
   129→    // Try to unlink a directory — EISDIR, not ENOENT
   130→    expect(() => safeUnlink(tmpDir)).toThrow();
   131→  });
   132→
   133→  it('concurrent reads of the same file — first succeeds, second gets ENOENT', () => {
   134→    const filePath = path.join(tmpDir, 'msg.json');
   135→    fs.writeFileSync(filePath, JSON.stringify({ type: 'message', text: 'hi' }));
   136→
   137→    // First reader succeeds
   138→    const data1 = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
   139→    expect(data1.type).toBe('message');
   140→
   141→    // First reader processes and deletes
   142→    fs.unlinkSync(filePath);
   143→
   144→    // Second reader gets ENOENT — should be handled gracefully
   145→    let skipped = false;
   146→    try {
   147→      fs.readFileSync(filePath, 'utf-8');
   148→    } catch (e: unknown) {
   149→      if ((e as NodeJS.ErrnoException).code === 'ENOENT') {
   150→        skipped = true;
   151→      }
   152→    }
   153→    expect(skipped).toBe(true);
   154→  });
   155→
   156→  it('readdirSync + processing handles file disappearing mid-loop', () => {
   157→    // Create files
   158→    fs.writeFileSync(path.join(tmpDir, 'a.json'), '{}');
   159→    fs.writeFileSync(path.join(tmpDir, 'b.json'), '{}');
   160→
   161→    const files = fs.readdirSync(tmpDir).filter((f) => f.endsWith('.json'));
   162→    expect(files).toHaveLength(2);
   163→
   164→    const processed: string[] = [];
   165→    for (const file of files) {
   166→      const filePath = path.join(tmpDir, file);
   167→      try {
   168→        fs.readFileSync(filePath, 'utf-8');
   169→        processed.push(file);
   170→        fs.unlinkSync(filePath);
   171→      } catch (e: unknown) {
   172→        if ((e as NodeJS.ErrnoException).code === 'ENOENT') continue;
   173→        throw e;
   174→      }
   175→    }
   176→
   177→    expect(processed).toHaveLength(2);
   178→  });
   179→});
