     3→
     4→export function escapeXml(s: string): string {
     5→  if (!s) return '';
     6→  return s
     7→    .replace(/&/g, '&amp;')
     8→    .replace(/</g, '&lt;')
     9→    .replace(/>/g, '&gt;')
    10→    .replace(/"/g, '&quot;');
    11→}
    12→
    13→export function formatMessages(
    14→  messages: NewMessage[],
    15→  timezone: string,
    16→): string {
    17→  const lines = messages.map((m) => {
    18→    const displayTime = formatLocalTime(m.timestamp, timezone);
    19→    return `<message sender="${escapeXml(m.sender_name)}" time="${escapeXml(displayTime)}">${escapeXml(m.content)}</message>`;
    20→  });
    21→
    22→  const header = `<context timezone="${escapeXml(timezone)}" />\n`;
    23→
    24→  return `${header}<messages>\n${lines.join('\n')}\n</messages>`;
    25→}
    26→
    27→export function stripInternalTags(text: string): string {
    28→  return text.replace(/<internal>[\s\S]*?<\/internal>/g, '').trim();
    29→}
    30→
    31→export function formatOutbound(rawText: string): string {
    32→  const text = stripInternalTags(rawText);
    33→  if (!text) return '';
    34→  return text;
    35→}
    36→
    37→export function routeOutbound(
    38→  channels: Channel[],
    39→  jid: string,
    40→  text: string,
    41→): Promise<void> {
    42→  const channel = channels.find((c) => c.ownsJid(jid) && c.isConnected());
    43→  if (!channel) throw new Error(`No channel for JID: ${jid}`);
    44→  return channel.sendMessage(jid, text);
    45→}
    46→
    47→export function findChannel(
    48→  channels: Channel[],
    49→  jid: string,
    50→): Channel | undefined {
    51→  return channels.find((c) => c.ownsJid(jid));
    52→}
