    17→// Statement cache: avoids recompiling SQL on every call.
    18→// Keyed by SQL string; cleared when database is (re)initialized.
    19→const stmtCache = new Map<string, Database.Statement>();
    20→function stmt(sql: string): Database.Statement {
    21→  let s = stmtCache.get(sql);
    22→  if (!s) {
    23→    s = db.prepare(sql);
    24→    stmtCache.set(sql, s);
    25→  }
    26→  return s;
    27→}
